// pages/Practice.jsx — Topic-wise practice questions
import React, { useState } from "react";
import { TOPICS } from "../data/topicsData";
import QuestionItem from "../components/QuestionItem";

export default function Practice() {
  const [selectedSlug, setSelectedSlug] = useState(TOPICS[0].slug);

  const topic = TOPICS.find((t) => t.slug === selectedSlug);

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      <h1 className="text-xl font-semibold text-white mb-1">Practice</h1>
      <p className="text-sm text-muted mb-8">
        Select a topic and work through the questions.
      </p>

      {/* Topic selector */}
      <div className="mb-8">
        <label className="block text-xs font-mono text-muted uppercase tracking-widest mb-2">
          Topic
        </label>
        <select
          value={selectedSlug}
          onChange={(e) => setSelectedSlug(e.target.value)}
          className="bg-surface border border-border text-sm text-gray-300 rounded px-3 py-2 focus:outline-none focus:border-accent transition-colors w-full sm:w-auto"
        >
          {TOPICS.map((t) => (
            <option key={t.slug} value={t.slug}>
              {t.name}
            </option>
          ))}
        </select>
      </div>

      {/* Divider */}
      <div className="border-t border-border mb-6" />

      {/* Questions */}
      {topic ? (
        <>
          <p className="text-xs font-mono text-muted mb-4">
            {topic.questions.length} question{topic.questions.length !== 1 ? "s" : ""}
          </p>
          {topic.questions.map((q, i) => (
            <QuestionItem key={q.id || i} question={q} index={i} />
          ))}
        </>
      ) : (
        <p className="text-muted text-sm">No questions available for this topic.</p>
      )}

      <div className="h-16" />
    </main>
  );
}
